import { getBaseUrl } from '@/shared/utils';
import { safeFetchJson } from '@/shared/neverthrow/fetch';

import { getBalanceOutputSchema } from '@agentcash/balance';

import type { GetBalanceInput } from '@agentcash/balance';
import type { GlobalFlags } from '@/types';

export const getBalance = async (
  surface: string,
  input: GetBalanceInput,
  flags: GlobalFlags
) => {
  return await safeFetchJson(
    surface,
    new Request(`${getBaseUrl(flags.dev)}/api/balance`, {
      method: 'POST',
      body: JSON.stringify(input),
      headers: {
        accept: 'application/json',
      },
    }),
    getBalanceOutputSchema
  );
};
