import { z } from 'zod';

import {
  ALL_NETWORK_CONFIGS,
  caip2ToNetwork,
  ethereumAddressSchema,
  EVM_CONFIGS,
  EvmNetwork,
  Network,
  networkSchema,
  SOLANA_CONFIG,
  solanaAddressSchema,
} from '@agentcash/networks';

const evmNetworks = Object.keys(EVM_CONFIGS) as EvmNetwork[];

export const getSolanaBalanceInputSchema = z.object({
  address: solanaAddressSchema,
  tokenAddress: solanaAddressSchema.optional(),
});

export const getEvmBalanceInputSchema = z.object({
  address: ethereumAddressSchema,
  tokenAddress: ethereumAddressSchema.optional(),
});

export const getBalanceInputSchema = z.discriminatedUnion('network', [
  getSolanaBalanceInputSchema.extend({
    network: z.literal(Network.SOLANA),
  }),
  getEvmBalanceInputSchema.extend({
    network: z.enum(evmNetworks),
  }),
]);

export const getBalanceOutputSchema = z.object({
  balance: z.number(),
  // this should be deprecated in the future
  network: z.enum(
    Object.values(ALL_NETWORK_CONFIGS).map(config => config.caip2)
  ),
  paymentNetwork: networkSchema,
  chainId: z.number(),
});

export type GetBalanceInput = z.infer<typeof getBalanceInputSchema>;
export type GetSolanaBalanceInput = Extract<
  GetBalanceInput,
  { network: typeof Network.SOLANA }
>;
export type GetEvmBalanceInput = Extract<
  GetBalanceInput,
  { network: EvmNetwork }
>;
export type GetBalanceOutput = z.infer<typeof getBalanceOutputSchema>;
